{"code": "import json

# Get the case history and case data
history_records = locals()['var_functions.query_db:12']
case_records = locals()['var_functions.query_db:10']

# Clean IDs (remove leading # and trailing whitespace)
def clean_id(id_val):
    if not id_val:
        return None
    if isinstance(id_val, str):
        return id_val.strip().lstrip('#')
    return str(id_val).strip().lstrip('#')

# Process transfers from case history
transfer_counts = {}
agent_cases = {}  # Track which cases each agent was involved with

# Count transfers (when oldvalue__c is not 'None')
for record in history_records:
    old_agent = clean_id(record['oldvalue__c'])
    new_agent = clean_id(record['newvalue__c'])
    case_id = clean_id(record['caseid__c'])

    if old_agent and old_agent != 'None':
        # This is a transfer FROM old_agent
        transfer_counts[old_agent] = transfer_counts.get(old_agent, 0) + 1

    # Track cases handled by each agent
    if old_agent and old_agent != 'None':
        if old_agent not in agent_cases:
            agent_cases[old_agent] = set()
        agent_cases[old_agent].add(case_id)

    if new_agent and new_agent != 'None':
        if new_agent not in agent_cases:
            agent_cases[new_agent] = set()
        agent_cases[new_agent].add(case_id)

# Also check case table for initial owners
case_owners = {}
for record in case_records:
    case_id = clean_id(record['id'])
    owner_id = clean_id(record['ownerid'])
    if case_id and owner_id:
        case_owners[case_id] = owner_id
        if owner_id not in agent_cases:
            agent_cases[owner_id] = set()
        agent_cases[owner_id].add(case_id)

# Filter agents who handled more than 0 cases
eligible_agents = {}
for agent_id, cases in agent_cases.items():
    if len(cases) > 0:
        eligible_agents[agent_id] = {
            'transfer_count': transfer_counts.get(agent_id, 0),
            'case_count': len(cases)
        }

# Find agent with minimum transfer count
if eligible_agents:
    min_transfer_agent = min(eligible_agents.keys(), key=lambda x: eligible_agents[x]['transfer_count'])
    result = {
        'agent_id': min_transfer_agent,
        'transfer_count': eligible_agents[min_transfer_agent]['transfer_count'],
        'case_count': eligible_agents[min_transfer_agent]['case_count'],
        'total_agents': len(eligible_agents)
    }
else:
    result = {'error': 'No eligible agents found'}

print('__RESULT__:')
print(json.dumps(result))"}

